import { Controller, Get, Post, Put, Delete, Param, Body } from '@nestjs/common';
import { ReviewService } from './review.service';
import { Review } from './review.entity';

@Controller('v5/review')
export class ReviewController {
  constructor(private readonly reviewService: ReviewService) {}

  @Get(':id')
  async getReview(@Param('id') id: string): Promise<Review> {
    return this.reviewService.findOne(id);
  }

  @Post()
  async createReview(@Body() reviewData: Review): Promise<Review> {
    return this.reviewService.create(reviewData);
  }

  @Put(':id')
  async updateReview(@Param('id') id: string, @Body() reviewData: Review): Promise<Review> {
    return this.reviewService.update(id, reviewData);
  }

  @Delete(':id')
  async deleteReview(@Param('id') id: string): Promise<void> {
    return this.reviewService.delete(id);
  }
}
